var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"저기 봐, 빌딩에 불이 붙었어!","JPN":"見て、あそこ！　ビルに火がついたぞ！","ENG":"Look, over there! The building's on fire!","TWN":"大家快看，大樓失火啦！"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"알파트릭스 건물이다! 뭐 해, 어서 찍어!","JPN":"アルファトリックスの建物だ！　何してんだ、早く撮れ！","ENG":"It's the Alphatrix building! What are you doing? We have to film it!","TWN":"是阿爾法崔克斯的大樓！還不趕快拍下來！"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"가스라도 폭발했나……? 누가 신고해야 하는 거 아냐?","JPN":"ガスでも爆発したのかな……？　誰か通報した方がよくない？","ENG":"Did they have a gas leak...? Hasn’t anyone called the police yet?","TWN":"是瓦斯氣爆嗎……？是不是該報警？"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"콜록……! 군용 폭발물이라도 입수했나? 어떻게 이렇게까지……?","JPN":"ゲホッ……！　軍用の爆発物でも入手したのかな？　なんでここまで……？","ENG":"*Cough...!* Did they get their hands on some military grade explosives? How did they even...?","TWN":"咳咳……！是軍隊在用的炸彈嗎？威力也太大……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이진 씨, 강소영 경위입니다! 안에 계신가요!","JPN":"シノザキ・ホノカさん、マエカワ・ナツミ警部補です！　中にいますか！","ENG":"Miss Lee? It's Lieutenant Kang! Are you in there?!","TWN":"李珍小姐，我姜素英警官！你在裡面嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"살아 있다면 대답하세요! 어서요!","JPN":"生きているなら返事してください！　早く！","ENG":"Say something if you're still there! Please!","TWN":"你還活著的話請回答！快說話！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"여기……. 이쪽입니다…….","JPN":"こち……こちらです……","ENG":"I'm... Over here...","TWN":"我……在這裡……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"구조대가 곧 올 거예요. 부축해 드리겠습니다.","JPN":"もうすぐ救助隊が到着します。肩をお貸しします。","ENG":"The rescue team is on their way. Here, let me help you.","TWN":"消防員很快就會抵達這裡，我扶你。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"잠시 정신을 잃긴 했지만…… 그래도 병원 신세를 질 만큼 다친 건 아니에요.","JPN":"しばらく気を失ってはいましたが……それでも病院に行くほどの怪我ではありません。","ENG":"I was knocked out for a few minutes, but... I don't think I’ll need to visit the hospital.","TWN":"我是有稍微失去意識……但還沒嚴重到需要進醫院的程度。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"이쪽의 근육 바보 먼저 챙겨 줘. 팔다리 한 짝씩 예쁘게 부러졌어.","JPN":"こっちの筋肉バカから助けてもらえるかしら。腕と足一本ずつキレイに折れてるわ。","ENG":"Take care of this musclehead. He broke an arm and a leg.","TWN":"先救救這個肌肉傻瓜吧，四肢斷得很徹底。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"근육 바보라니! 아야야야……!","JPN":"筋肉バカって！　あたたた……！","ENG":"Musclehead?! Ouch...!","TWN":"你說誰是肌肉傻瓜！哎呀呀呀呀……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"카운터가 있는 줄 알았다면 위험을 감수해서라도 최대한 빠르게 제압했을 거예요.","JPN":"カウンターがいることを知っていれば、危険を冒してでもなるべく早く制圧しようとしたはずです。","ENG":"If I had known they had a Counter, I would have taken them on as quickly as possible, despite the risks.","TWN":"早知道當中有制裁者，就算冒著危險也要儘速壓制他們才對。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"모두 제 불찰입니다.","JPN":"すべて私のミスです。","ENG":"It's all my fault.","TWN":"都是我的疏失。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"카운터요? 방금 제가 제대로 들은 거 맞나요?","JPN":"カウンターですか？　今の私の聞き間違いじゃないですよね？","ENG":"A Counter? Did I hear that right?","TWN":"制裁者？我有聽錯嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"네. 용병 분들이 다른 두 명을 견제하는 동안, 제가 제압하려 했던 여성 민병대원이 손에서 불길을 일으키더군요.","JPN":"はい。傭兵の方々が他の二人をマークしている間、私が女性の民兵隊員を制圧しようとしたのですが、その者の手から炎が出たのです。  ","ENG":"Yes. While our mercenaries were dealing with the other two, the girl I was fighting had fire coming out of her hands.","TWN":"沒錯，傭兵在對付其中二名隊員時，我負責的那名女性民兵隊員手上有火苗。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"저도 불을 다루는 데 나름 조예가 있는 편입니다.","JPN":"私も炎を扱うことについてはそれなりに自信のある方です。","ENG":"You see, I'm also familiar with handling fire.","TWN":"我個人對火的事也是略懂略懂。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"카운터의 능력인지, 아니면 다른 모종의 기술인지는 얼핏만 봐도 알 수 있어요.","JPN":"カウンターの能力なのか、それともそれ以外のある種の技術なのかは少し見ればわかります。","ENG":"I could tell even at just a glance whether it was a Counter ability or some other kind of skill.","TWN":"一看就知道是制裁者的能力，還是某種魔術。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"고등급 카운터가 고작 차가 폭발했다고 이런 꼴이 되진 않아.","JPN":"高ランクカウンターがたかだか車の爆発でこんな姿にはならない。","ENG":"A high-grade Counter doesn't end up like this just because a car exploded.","TWN":"高等級制裁者不會因為車輛爆炸而變成這副模樣。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"게다가 살인사건에서 살해 흔적을 남기지 않았다는 건, 전형적인 카운터 범죄의 케이스지.","JPN":"しかも、殺害の痕跡を残さなかったということは、典型的なカウンター犯罪のケースでしょうね。","ENG":"And the lack of any traces implies that this is a case of typical Counter crime.","TWN":"而且這種殺人不留痕跡的手法，是典型的制裁者犯罪。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"범인은 카운터일 가능성이 높아.","JPN":"犯人はカウンターである可能性が高い。","ENG":"It's highly likely that the suspect is a Counter.","TWN":"犯人很可能是制裁者。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"오오, 거기까지 생각하셨다니. 경정님도 실력이 꽤 느셨는데요?","JPN":"おお、そこまで考えていたとは。警視様もなかなか成長したものですね。","ENG":"Ooh, you thought that far already? You're getting pretty good at this!","TWN":"噢噢，竟然想到那種地步，警正的實力也進步不少哦？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"어디까지나 추측이야, 추측! 아닐 수도 있다고!","JPN":"あくまで推測よ、推測！　違うかもしれないし。","ENG":"It's all just a hunch! I could be wrong!","TWN":"只是推測而已，推測！也有可能不是！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"사건 수사가 다 그렇게 시작하는 거죠, 뭘.","JPN":"事件捜査って最初はそういうところから始まるものですよ。","ENG":"Well, all cases start with a hunch after all.","TWN":"調查案件不都是這樣起步的嗎？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"역시…….","JPN":"やっぱりね……","ENG":"I knew it...","TWN":"果然……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그런데 같이 다니시던 분은 어디 계시죠?","JPN":"ところで、一緒にいた方はどちらに？","ENG":"But where's the other person who was with you?","TWN":"不過和你一起的行動的警官呢？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"폭발이 일어났을 때 뭔가를 보고 먼저 움직이셨어요. 아마 민병대를 발견하신 거겠죠.","JPN":"爆発が発生したときに何かを見て、先に動いていました。多分民兵隊を発見したんでしょう。","ENG":"She saw something when the explosion happened and chased after it. I'm assuming that she found the Militia.","TWN":"爆炸發生時，她不知道看到什麼就立刻衝出去，可能是發現到民兵隊吧？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 그들 중에 카운터가 있다면……","JPN":"でも彼らの中にカウンターがいるのなら……","ENG":"But if there's a Counter within the Militia...","TWN":"但他們當中有制裁者的話……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님, 응답하세요. 경정님?","JPN":"警視様、応答してください。警視様？","ENG":"Major? Major?! Come in!","TWN":"警正，聽到請回答，警正？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"크으…….","JPN":"くぅ……","ENG":"Kgh...","TWN":"咳……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"민우 대장, 괜찮아요?","JPN":"マツダ隊長、大丈夫ですか？","ENG":"Captain, you good?","TWN":"民宇隊長，你還好嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그러게 차라리 그냥 업히라니까요. 잘못 움직이다 뼈 부러진 게 어디 잘못 찌르면 진짜 죽어요.","JPN":"だから私が背負ってあげますって言ったのに。下手に動いて折れた骨がまずい所にでも刺さったら本当に死にますよ。","ENG":"See, I told you to just get on my back. One wrong move, and you could really die from a stab by your own broken bone.","TWN":"乾脆我揹你啦！萬一你到時候骨折，骨頭又刺到哪裡的話真的會死掉欸！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"총 맞은 주제에 누굴 걱정해. 네 몸이나 잘 챙겨.","JPN":"銃に撃たれたくせに人の心配してる場合か。自分の身を心配しろ。","ENG":"Says the girl who got shot. I'm fine. Take care of yourself.","TWN":"你還有餘力擔心我嗎？你自己還不是中槍，先顧好你自己吧！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"네, 덕분에 아픈 게 슬금슬금 올라오네요. 고마워 죽겠어, 아주.","JPN":"はいはい、おかげさまでじわじわ痛くなってきてます。ありがたすぎてどうしたらよいやら、はあ。","ENG":"Sure. Thanks for reminding me. I think the pain is starting to come back now.","TWN":"謝謝你的提醒喔，我現在慢慢有痛的感覺了，太感謝你啦！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그렇게 풀죽은 표정 짓지 마라. 네가 그 힘을 조절 못하는 건 나도 잘 알아.","JPN":"そうへこむな。お前があの力を調節できないことは俺もよくわかっている。","ENG":"Don't look so glum. I know you're still not able to control your powers.","TWN":"不需要一臉難過的樣子，我很清楚你還無法控制那股力量。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"하지만 결국 그것 때문에 대장까지 휘말려 버렸잖아.","JPN":"でも結局そのせいで隊長まで巻き込んで……","ENG":"But you ended up getting hurt because of me.","TWN":"可是最後還拖累到隊長！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"네가 일으킨 폭발이 아니었으면 우리 모두 지금쯤 유치장에 처박혀 있었어.","JPN":"お前が爆発を起こさなかったら、俺たち全員今頃は留置場にいたはずだ。","ENG":"If it weren't for the explosion you caused, we'd all be behind bars right now.","TWN":"要不是你引發爆炸，我們可能都難逃牢獄之災。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이 정도면, 보석금으론 싸게 먹힌 셈이니까……. 크음…….","JPN":"このくらいなら、保釈金としては安くついたわけだ……くう……","ENG":"I’d say it's a better deal than posting bail... Khhm...","TWN":"受點傷就不用付保釋金，划得來啦……咳咳……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"세상에. 언니, 민우 대장 식은땀 흐르는 것 좀 봐. 이러다 진짜 길바닥에서 객사하겠어요.","JPN":"どうしよう、ユリさん。マツダ隊長の冷や汗がすごいですよ。このままじゃあ、本当に路上で死ぬかも。","ENG":"Oh gosh... Yuri, Captain's sweating so much. I think he might really die out on the streets at this rate.","TWN":"我的天，姊姊，民宇隊長渾身在冒冷汗，再這樣下去他真的會橫死街頭啦！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……역시 이대로는 안 되겠어.","JPN":"……やっぱりこのままじゃダメだ。","ENG":"...We can't let that happen.","TWN":"……這樣不行，"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"차를 구해 올게. 레비아 넌 그동안 대장과 잠시 숨어 있어.","JPN":"車を探してくる。レヴィアはその間しばらく隊長と隠れていて。","ENG":"I'll go find us a car. Levia, take Captain and hide somewhere safe.","TWN":"我去弄台車來，在我回來之前，你先和隊長躲起來。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"이건……?!","JPN":"これは……！？","ENG":"Huh...?!","TWN":"這是……？！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"건물을 파괴했으니까 절도는 문제도 아니란 거야? 뻔뻔하긴.","JPN":"建物を破壊したから、もう窃盗くらいは何でもないってこと？　図々しいわね。","ENG":"Are you saying theft isn't a problem because you already destroyed a building? How shameless.","TWN":"反正都已經炸掉一棟大樓，再偷個東西也不算什麼是吧？真是厚顏無恥！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"오랜만에 다시 만났네, 범죄자들.","JPN":"久しぶり。また会ったわね、犯罪者ども。","ENG":"Long time no see, criminals.","TWN":"又見面啦，你們這些罪犯！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님, 응답하세요. 경정님?","JPN":"警視様、応答してください。警視様？","ENG":"Major? Major?! Come in!","TWN":"警正，聽到請回答，警正？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"용의자들과 대치 중이야. 용건만 짧게 말해, 강소영 경위.","JPN":"容疑者たちと対峙してる。短く用件だけ話して、マエカワ警部補。","ENG":"I'm confronting the suspects. Make it quick, Lieutenant.","TWN":"我正在嫌犯對峙中，長話短說，姜素英員警。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아차……. 벌써 따라잡으셨어요?","JPN":"おっと……もう追いつきました？","ENG":"Oh... You already found them?","TWN":"哇喔……你已經追到人啦？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"조심하세요. 민병대 중에 카운터가 섞여 있어요.","JPN":"気をつけてください。民兵隊の中にカウンターがいます。","ENG":"Be careful. There's a Counter among them.","TWN":"小心一點，民兵隊當中有制裁者。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"카운터라고?","JPN":"カウンターですって？","ENG":"A Counter?","TWN":"制裁者？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"레비아. 대장을 데리고 먼저 가.","JPN":"レヴィア。隊長を連れて先に行け。","ENG":"Levia, take Captain and go.","TWN":"莉維亞，你先帶隊長走！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"저 애, 라디오에 나왔던 그 경찰 소속 카운터 맞지? 설마 언니 혼자 막으려고요?","JPN":"あの子、ラジオに出てたあの警察所属のカウンターですよね？　まさかユリさん一人で止める気ですか？","ENG":"That girl... Isn't she the police Counter we heard on the radio? And you're going to stop her all by yourself?","TWN":"她就是廣播裡的那個警察制裁者吧？你該不會是想自己對付她吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"더 숨길 생각 없어. 내 힘은 너도 봐서 알잖아.","JPN":"もう隠すつもりはない。私の力は見て知ってるだろう。","ENG":"I'm not going to hide any longer. You’ve seen what I could do.","TWN":"我不打算再躲藏下去，你也有看到我的能力吧！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"제대로 다루지도 못하면서 큰소리는. 그게 안전 장치 없는 미사일이랑 뭐가 달라요?","JPN":"ちゃんと扱えないくせに見栄張って。それって安全装置のないミサイルも同じでしょ？","ENG":"But you can't even control it...! How's it any different from a missile without a safety pin?!","TWN":"你根本都還控制不好，還在那邊大聲什麼！那跟沒有安全裝置的導彈有什麼二樣？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그래. 그러니까 휘말리지 말라는 거야.","JPN":"そう。だから巻き込まれないようにしろってこと。","ENG":"Exactly my point. That's why I'm telling you to get out of here.","TWN":"沒錯，所以我才不想波及你們。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"동생을 찾는다고 했지?","JPN":"妹を探してるって言ったよね？","ENG":"Didn't you say you were looking for your younger sister?","TWN":"你說你在找妹妹對吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그럼 어떻게든 살아서 만날 생각을 해. 나는 해냈으니까. ","JPN":"じゃあ、なんとか生き延びて会うことだけ考えろ。私は成功したから。 ","ENG":"Then find a way to stay alive until you do. Because that's what I did. ","TWN":"那就想著無論如何都要活著相見，我已經達成這個心願。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……그렇게 마음에 들지 않는 형태지만.","JPN":"……気に入らない形ではあるけど。  ","ENG":"...Although, I didn't want it that way.","TWN":"……雖然和我期待的有落差。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"응? 그 말은 저 애가…….","JPN":"え？　それじゃ、あの子が……","ENG":"Hmm? Are you saying that she's...","TWN":"嗯？這個意思是，她……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"알겠어. 먼저 갈 테니까 합류지점에서 봐요.","JPN":"わかりました。先に行くから合流地点でね。","ENG":"All right. I'll go ahead. I'll see you at the rendezvous point.","TWN":"好，那我們先走，之後集合地點見！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"잠깐! 도망칠 수 있다고 생각해?!","JPN":"待ちなさい！　逃げられると思ってるの！？","ENG":"Wait! Do you really think you can run away from me?!","TWN":"站住！你以為你們逃得掉嗎？！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"여태 허탕친 게 아쉽겠지만, 그렇다고 줄줄이 엮어 들어갈 수는 없어. 이유미 경정.","JPN":"これまで何もできなかったのは残念だろうけど、だからと言ってみんな一緒に捕まるわけにはいかない。カスカベ・ユミ警視。","ENG":"As much as you want to arrest all of us, we're not going to let you get us that easily, Major Lee Yumi.","TWN":"很遺憾，至今一直讓你們白忙一場，但我們也無法乖乖跟你走，李悠美警正。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"절도 모의에 공무집행 방해까지. 범죄가 생활화된 수준이네.","JPN":"窃盗の謀議に公務執行妨害まで。犯罪が身にしみついているようね。","ENG":"Attempted robbery and now obstructing police? Well, aren't you a walking rap sheet?","TWN":"涉嫌竊盜還不夠，再加上一條妨礙公務罪，犯罪根本就是你的日常吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"총 내려놓고 얌전히 수갑이나 차. 변호사 알아 보려면 오래 걸릴 테니까.","JPN":"銃を下ろして大人しく逮捕されなさい。弁護士を探すのに時間がかかるからね。","ENG":"Put down the gun and put on these handcuffs. It's going to take a while for you to find a lawyer.","TWN":"把槍放下，乖乖上手銬，找律師會需要很長的時間。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"이거라도 안 겨누면 날 변호해 주겠다고 나설 놈이 있기나 한가?","JPN":"銃を構えてなかったら弁護してやる、って奴もいないはずだが？","ENG":"Will anyone come forward to defend me if I don't aim this at you?","TWN":"要是沒這把槍，哪個傢伙會願意替我辯護？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"따분한 소리 집어치우고 덤벼. 오랫동안 잡고 싶었잖아?","JPN":"くだらない話はやめてかかって来い。ずっと捕まえたかったんだろう？","ENG":"Enough with the chitchat. Come at me. You wanted to catch me for a long time, right?","TWN":"廢話少說，來吧，你不是一直很想抓我嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"흥. 그렇게 나오겠단 말이지.","JPN":"ふん。そう来るってこと？","ENG":"Hmph. If that's how you want to do this, then...","TWN":"哼，你要這樣是吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그럼 각오해! 나중에 과잉 진압이라고 불평하지나 말라구!","JPN":"じゃあ、覚悟しなさい！　後で過剰鎮圧だのなんの文句言わないでよね！","ENG":"You asked for it! Don't complain about police brutality later, all right?!","TWN":"那就覺悟吧！之後可不要怪我執法過當！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};